function queueOperations(operations, values) {
  const inbox = [];
  const outbox = [];
  const results = [];
  function transfer() {
    if (outbox.length > 0) return;
    while (inbox.length > 0) outbox.push(inbox.pop());
  }
  for (let i = 0; i < operations.length; i++) {
    const op = operations[i];
    const args = values[i];
    if (op === 'push') {
      inbox.push(args[0]);
      results.push(null);
      continue;
    }
    if (op === 'pop') {
      transfer();
      results.push(outbox.pop());
      continue;
    }
    if (op === 'peek') {
      transfer();
      results.push(outbox[outbox.length - 1]);
      continue;
    }
    if (op === 'empty') {
      results.push(inbox.length === 0 && outbox.length === 0);
      continue;
    }
  }
  return results;
}
